let inventoryProducts = [];
let customerDatabase  = [];
let _stampBase64      = "data:image/png;base64,";
let rowCounter        = 0;

const ROWS_PER_FIRST_PAGE = 12;
const ROWS_PER_EXTRA_PAGE = 20;

/* -------------------------------------------
   STAMP PRELOADER
------------------------------------------- */
function loadStampAsBase64() {
  if (_stampBase64 && _stampBase64.startsWith("data:image/")) {
    return Promise.resolve(_stampBase64);
  }
  return new Promise(resolve => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = function () {
      try {
        const c = document.createElement("canvas");
        c.width  = img.naturalWidth  || 300;
        c.height = img.naturalHeight || 300;
        c.getContext("2d").drawImage(img, 0, 0);
        _stampBase64 = c.toDataURL("image/png");
        resolve(_stampBase64);
      } catch (e) {
        console.warn("Could not convert stamp to base64 (possibly CORS/file:// security):", e);
        _stampBase64 = "";
        resolve("");
      }
    };
    img.onerror = () => { _stampBase64 = ""; resolve(""); };
    img.src = "assets/stamp.png?" + Date.now();
  });
}

/* -------------------------------------------
   INVOICE NUMBER GENERATOR
------------------------------------------- */
function generateInvoiceNumber() {
  const ts = Date.now().toString();
  return "INV-" + ts.substring(ts.length - 8);
}

