/* -------------------------------------------
   FETCH AUTOCOMPLETE DATA
------------------------------------------- */
async function fetchAutocompleteData() {
  try {
    const [invData, custData] = await Promise.all([
      getCachedData("inventory"),
      getCachedData("customers")
    ]);
    inventoryProducts = invData;
    customerDatabase  = custData;

    const sel = document.getElementById("customerSelect");
    if (sel) {
      sel.innerHTML = `<option value="">— Select Customer —</option>` +
        customerDatabase.map(c => `<option value="${c.customerId}">${c.name} (${c.phone})</option>`).join("");
      makeSearchableSelect(sel, "— Select Customer —");
    }

    // Refresh all product selects in the form
    refreshProductSelects();
  } catch (err) {
    console.error("Autocomplete data error:", err);
  }
}

/* -------------------------------------------
   CUSTOMER DROPDOWN CHANGE
------------------------------------------- */
function handleCustomerDropdownChange(sel) {
  const id = sel.value;
  const fld = (id) => document.getElementById(id);
  if (!id) {
    fld("invoiceCustomerName").value    = "";
    fld("invoiceCustomerPhone").value   = "";
    fld("invoiceCustomerEmail").value   = "";
    fld("invoiceCustomerAddress").value = "";
    return;
  }
  const c = customerDatabase.find(x => x.customerId === id);
  if (c) {
    fld("invoiceCustomerName").value    = c.name    || "";
    fld("invoiceCustomerPhone").value   = c.phone   || "";
    fld("invoiceCustomerEmail").value   = c.email   || "";
    fld("invoiceCustomerAddress").value = c.address || "";
  }
}

/* -------------------------------------------
   ADD ROW — desktop table + mobile card
------------------------------------------- */
