/* -------------------------------------------
   REMOVE ROW
------------------------------------------- */
function removeInvoiceRow(rid) {
  const tr   = document.getElementById(rid);
  const card = document.getElementById("mc-" + rid);
  if (tr)   tr.remove();
  if (card) card.remove();
  calculateAllTotals();
}

/* -------------------------------------------
   PRODUCT SELECT — auto-fill rate/unit/cgst/sgst
------------------------------------------- */
function onProductSelect(rid, sel) {
  const opt  = sel.options[sel.selectedIndex];
  const rate = parseFloat(opt.dataset.rate) || 0;
  const unit = opt.dataset.unit || "Nos";
  const cgst = parseFloat(opt.dataset.cgst) || 9;
  const sgst = parseFloat(opt.dataset.sgst) || 9;
  const stock= parseFloat(opt.dataset.stock) || 0;

  // Sync to desktop row
  const tr = document.getElementById(rid);
  if (tr) {
    tr.querySelector(".rate").value = rate.toFixed(2);
    tr.querySelector(".unit").value = unit;
    tr.querySelector(".cgst").value = cgst;
    tr.querySelector(".sgst").value = sgst;
    // also sync the desktop select
    const dSel = tr.querySelector(".inv-sel");
    if (dSel && dSel !== sel) dSel.value = sel.value;
  }

  // Sync to mobile card
  const card = document.getElementById("mc-" + rid);
  if (card) {
    card.querySelector(".m-rate").value = rate.toFixed(2);
    card.querySelector(".m-unit").value = unit;
    card.querySelector(".m-cgst").value = cgst;
    card.querySelector(".m-sgst").value = sgst;
    const mSel = card.querySelector(".m-sel");
    if (mSel && mSel !== sel) mSel.value = sel.value;
  }

  if (stock <= 0) {
    showToast(`⚠️ Out of stock!`, "warn");
  } else if (stock < 10) {
    showToast(`⚠️ Low stock: ${stock} units left`, "warn");
  }

  calcRow(rid);
}

/* -------------------------------------------
   SYNC MOBILE → DESKTOP
------------------------------------------- */
function syncCard(rid, field, value) {
  const tr = document.getElementById(rid);
  if (!tr) return;
  const map = { qty:"qty", unit:"unit", rate:"rate", disc:"disc", cgst:"cgst", sgst:"sgst" };
  const inp = tr.querySelector("." + map[field]);
  if (inp) inp.value = value;
  calcRow(rid);
}

/* -------------------------------------------
   CALCULATE A SINGLE ROW
------------------------------------------- */
function calcRow(rid) {
  const tr   = document.getElementById(rid);
  const card = document.getElementById("mc-" + rid);
  if (!tr) return;

  const sel = tr.querySelector(".inv-sel");
  const opt = sel ? sel.options[sel.selectedIndex] : null;
  const stock = (opt && opt.value !== "") ? parseFloat(opt.dataset.stock) || 0 : 999999;

  const qtyInput = tr.querySelector(".qty");
  let qty = parseFloat(qtyInput.value) || 0;

  if (qty < 0) {
    showToast("⚠️ Quantity cannot be negative.", "warn");
    qtyInput.value = 0;
    qty = 0;
    if (card) {
      const mQty = card.querySelector(".m-qty");
      if (mQty) mQty.value = 0;
    }
  }

  if (opt && opt.value !== "") {
    if (stock <= 0 && qty > 0) {
      showToast(`⚠️ Out of stock! Cannot bill ${opt.text}.`, "error");
      qtyInput.value = 0;
      qty = 0;
      if (card) {
        const mQty = card.querySelector(".m-qty");
        if (mQty) mQty.value = 0;
      }
    } else if (qty > stock) {
      const capped = Math.max(0, stock);
      showToast(`⚠️ Insufficient stock for ${opt.text}! Available: ${stock}`, "error");
      qtyInput.value = capped;
      qty = capped;
      if (card) {
        const mQty = card.querySelector(".m-qty");
        if (mQty) mQty.value = capped;
      }
    }
  }

  const rateInput = tr.querySelector(".rate");
  let rate = parseFloat(rateInput.value) || 0;
  if (rate < 0) {
    showToast("⚠️ Rate cannot be negative.", "warn");
    rateInput.value = 0;
    rate = 0;
    if (card) {
      const mRate = card.querySelector(".m-rate");
      if (mRate) mRate.value = 0;
    }
  }

  const discInput = tr.querySelector(".disc");
  let disc = parseFloat(discInput.value) || 0;
  if (disc < 0) {
    showToast("⚠️ Discount cannot be negative.", "warn");
    discInput.value = 0;
    disc = 0;
    if (card) {
      const mDisc = card.querySelector(".m-disc");
      if (mDisc) mDisc.value = 0;
    }
  } else if (disc > 100) {
    showToast("⚠️ Max discount is 100%.", "warn");
    discInput.value = 100;
    disc = 100;
    if (card) {
      const mDisc = card.querySelector(".m-disc");
      if (mDisc) mDisc.value = 100;
    }
  }

  const cgstInput = tr.querySelector(".cgst");
  let cgst = parseFloat(cgstInput.value) || 0;
  if (cgst < 0) {
    showToast("⚠️ CGST cannot be negative.", "warn");
    cgstInput.value = 0;
    cgst = 0;
    if (card) {
      const mCgst = card.querySelector(".m-cgst");
      if (mCgst) mCgst.value = 0;
    }
  } else if (cgst > 100) {
    showToast("⚠️ Max CGST is 100%.", "warn");
    cgstInput.value = 100;
    cgst = 100;
    if (card) {
      const mCgst = card.querySelector(".m-cgst");
      if (mCgst) mCgst.value = 100;
    }
  }

  const sgstInput = tr.querySelector(".sgst");
  let sgst = parseFloat(sgstInput.value) || 0;
  if (sgst < 0) {
    showToast("⚠️ SGST cannot be negative.", "warn");
    sgstInput.value = 0;
    sgst = 0;
    if (card) {
      const mSgst = card.querySelector(".m-sgst");
      if (mSgst) mSgst.value = 0;
    }
  } else if (sgst > 100) {
    showToast("⚠️ Max SGST is 100%.", "warn");
    sgstInput.value = 100;
    sgst = 100;
    if (card) {
      const mSgst = card.querySelector(".m-sgst");
      if (mSgst) mSgst.value = 100;
    }
  }

  const gross    = qty * rate;
  const discAmt  = gross * disc / 100;
  const afterDisc= gross - discAmt;
  const cgstAmt  = afterDisc * cgst / 100;
  const sgstAmt  = afterDisc * sgst / 100;
  const taxAmt   = cgstAmt + sgstAmt;
  const rowTotal = afterDisc + taxAmt;

  // Desktop read-only cells
  tr.querySelector(".discAmt").textContent  = discAmt.toFixed(2);
  tr.querySelector(".taxAmt").textContent   = taxAmt.toFixed(2);
  tr.querySelector(".rowTotal").textContent = rowTotal.toFixed(2);

  // Mobile card
  if (card) {
    card.querySelector(".m-discAmt").textContent  = "₹" + discAmt.toFixed(2);
    card.querySelector(".m-taxAmt").textContent   = "₹" + taxAmt.toFixed(2);
    card.querySelector(".m-rowTotal").textContent = "₹" + rowTotal.toFixed(2);
  }

  calculateAllTotals();
}

/* -------------------------------------------
   CALCULATE GRAND TOTALS
------------------------------------------- */
function calculateAllTotals() {
  let subtotal = 0, totalDisc = 0, totalCGST = 0, totalSGST = 0;

  document.querySelectorAll("#invDesktopBody tr").forEach(tr => {
    const qty    = parseFloat(tr.querySelector(".qty")  ?.value) || 0;
    const rate   = parseFloat(tr.querySelector(".rate") ?.value) || 0;
    const disc   = parseFloat(tr.querySelector(".disc") ?.value) || 0;
    const cgst   = parseFloat(tr.querySelector(".cgst") ?.value) || 0;
    const sgst   = parseFloat(tr.querySelector(".sgst") ?.value) || 0;

    const gross    = qty * rate;
    const discAmt  = gross * disc / 100;
    const afterDisc= gross - discAmt;
    totalDisc  += discAmt;
    subtotal   += afterDisc;
    totalCGST  += afterDisc * cgst / 100;
    totalSGST  += afterDisc * sgst / 100;
  });

  const grandTotal = subtotal + totalCGST + totalSGST;
  const rounded    = Math.round(grandTotal);

  const fmt = v => "₹" + v.toFixed(2);
  const setEl = (id, val) => { const el = document.getElementById(id); if (el) el.textContent = val; };

  setEl("invSubtotal",  fmt(subtotal));
  setEl("invTotalDisc", fmt(totalDisc));
  setEl("invTotalCGST", fmt(totalCGST));
  setEl("invTotalSGST", fmt(totalSGST));
  setEl("invGrandTotal","₹" + rounded.toFixed(2));
  setEl("invAmountWords", numberToWords(rounded) + " Rupees Only");
}

/* -------------------------------------------
   GATHER ITEMS FOR POST / PDF
------------------------------------------- */
function gatherItems() {
  return Array.from(document.querySelectorAll("#invDesktopBody tr")).map(tr => {
    const sel  = tr.querySelector(".inv-sel");
    const pid  = sel ? sel.value : "";
    const pName = sel ? (sel.options[sel.selectedIndex]?.text || "") : "";

    const qty    = parseFloat(tr.querySelector(".qty")  ?.value) || 0;
    const unit   = tr.querySelector(".unit") ?.value || "Nos";
    const rate   = parseFloat(tr.querySelector(".rate") ?.value) || 0;
    const disc   = parseFloat(tr.querySelector(".disc") ?.value) || 0;
    const cgst   = parseFloat(tr.querySelector(".cgst") ?.value) || 0;
    const sgst   = parseFloat(tr.querySelector(".sgst") ?.value) || 0;

    const gross    = qty * rate;
    const discAmt  = gross * disc / 100;
    const afterDisc= gross - discAmt;
    const cgstAmt  = afterDisc * cgst / 100;
    const sgstAmt  = afterDisc * sgst / 100;
    const taxAmt   = cgstAmt + sgstAmt;
    const total    = afterDisc + taxAmt;

    return { productId:pid, productName:pName, qty, unit, rate, discount:disc,
             discAmount:discAmt, cgst, sgst, cgstAmt, sgstAmt, afterDisc, taxAmt, total };
  });
}

/* -------------------------------------------
   NUMBER → WORDS (Indian system)
------------------------------------------- */
function numberToWords(num) {
  const ones = ["","One","Two","Three","Four","Five","Six","Seven","Eight","Nine",
                "Ten","Eleven","Twelve","Thirteen","Fourteen","Fifteen","Sixteen",
                "Seventeen","Eighteen","Nineteen"];
  const tens = ["","","Twenty","Thirty","Forty","Fifty","Sixty","Seventy","Eighty","Ninety"];
  function lt1000(n) {
    let s = "";
    if (n >= 100) { s += ones[Math.floor(n/100)] + " Hundred "; n %= 100; }
    if (n >= 20)  { s += tens[Math.floor(n/10)]  + " "; n %= 10; }
    if (n > 0)    { s += ones[n] + " "; }
    return s;
  }
  if (num === 0) return "Zero";
  let r = "";
  if (Math.floor(num/10000000) > 0) { r += lt1000(Math.floor(num/10000000)) + "Crore "; num %= 10000000; }
  if (Math.floor(num/100000)   > 0) { r += lt1000(Math.floor(num/100000))   + "Lakh ";  num %= 100000;   }
  if (Math.floor(num/1000)     > 0) { r += lt1000(Math.floor(num/1000))     + "Thousand "; num %= 1000;   }
  if (num > 0)                      { r += lt1000(num); }
  return r.trim();
}

/* -------------------------------------------
   TOAST NOTIFICATION
------------------------------------------- */
function showToast(msg, type = "info") {
  let t = document.getElementById("sre-toast");
  if (!t) {
    t = document.createElement("div");
    t.id = "sre-toast";
    document.body.appendChild(t);
  }
  t.textContent = msg;
  t.className = "sre-toast sre-toast-" + type + " sre-toast-show";
  clearTimeout(t._timer);
  t._timer = setTimeout(() => t.classList.remove("sre-toast-show"), 3000);
}

/* -------------------------------------------
   BUILD INVOICE PAGE HTML (for PDF/print)
------------------------------------------- */
function buildInvoicePageHTML(items, pageIdx, totalPages, companyInfo, custInfo, amountWords) {
  const isFirst = pageIdx === 0;
  const isLast  = pageIdx === totalPages - 1;

  const header = isFirst ? `
    <div class="invoice-header">
      <div>
        <h2>${companyInfo.name}</h2>
        <p>Authorized Dealers in CRI Pumps, Sudhakar Pipes and Polycab Wires</p>
        <p>${companyInfo.address}</p>
        <p>GST: ${companyInfo.gst} &nbsp;|&nbsp; Ph: ${companyInfo.phone}</p>
      </div>
      <div class="invoice-title">INVOICE</div>
    </div>
    <div class="customer-section">
      <div>
        <strong>Billed To:</strong><br>
        ${custInfo.name}<br>
        ${custInfo.address}<br>
        Ph: ${custInfo.phone}<br>
        ${custInfo.email}
      </div>
      <div style="text-align:right;">
        <strong>Invoice No:</strong> ${custInfo.invoiceNo}<br>
        <strong>Date:</strong> ${custInfo.date}
      </div>
    </div>
  ` : `
    <div class="invoice-header">
      <div><h2>${companyInfo.name}</h2>
        <p>Invoice No: ${custInfo.invoiceNo} | Date: ${custInfo.date} | Page ${pageIdx+1} of ${totalPages}</p>
      </div>
      <div class="invoice-title" style="font-size:18px;">INVOICE (Contd.)</div>
    </div>
  `;

  let offset = pageIdx === 0 ? 0 : ROWS_PER_FIRST_PAGE + (pageIdx-1)*ROWS_PER_EXTRA_PAGE;

  const rows = items.map((p, i) => `
    <tr>
      <td>${offset + i + 1}</td>
      <td style="text-align:left">${p.productName}</td>
      <td>${p.qty}</td>
      <td>${p.unit}</td>
      <td>${p.rate.toFixed(2)}</td>
      <td>${p.discount}%</td>
      <td>${p.discAmount.toFixed(2)}</td>
      <td>${p.cgst}%</td>
      <td>${p.sgst}%</td>
      <td>${p.taxAmt.toFixed(2)}</td>
      <td>${p.total.toFixed(2)}</td>
    </tr>
  `).join("");

  let summary = "";
  if (isLast) {
    const all = gatherItems();
    let sub=0, disc=0, cg=0, sg=0;
    all.forEach(p => { sub+=p.afterDisc; disc+=p.discAmount; cg+=p.cgstAmt; sg+=p.sgstAmt; });
    const gt  = sub + cg + sg;
    const rnd = Math.round(gt) - gt;
    const fin = Math.round(gt);
    summary = `
      <tr class="summary-row"><td colspan="10" style="text-align:right">Sub Total (without tax)</td><td>${(sub + disc).toFixed(2)}</td></tr>
      <tr class="summary-row"><td colspan="10" style="text-align:right">Taxable Amount</td><td>${sub.toFixed(2)}</td></tr>
      <tr class="summary-row"><td colspan="10" style="text-align:right">CGST</td><td>${cg.toFixed(2)}</td></tr>
      <tr class="summary-row"><td colspan="10" style="text-align:right">SGST</td><td>${sg.toFixed(2)}</td></tr>
      <tr class="summary-row"><td colspan="10" style="text-align:right">Round Off</td><td>${rnd.toFixed(2)}</td></tr>
      <tr class="grand-total"><td colspan="10" style="text-align:right">GRAND TOTAL (subtotal+tax)</td><td>₹ ${fin.toFixed(2)}</td></tr>
    `;
  }

  const stamp = _stampBase64
    ? `<img src="${_stampBase64}" alt="Stamp" style="width:130px;height:auto;">`
    : ``;

  const footer = isLast ? `
    <div class="amount-words"><strong>Amount in Words:</strong> ${amountWords}</div>
    <div class="signature-section">
      ${stamp}
      <div>Authorized Signature<br>For Seetha Rama Electricals</div>
    </div>
    <div class="footer-note">Goods once sold will not be taken back. Thank you for your business!</div>
  ` : `<div class="footer-note">Continued on next page…</div>`;

  return `
    <div class="invoice-page">
      <div class="watermark">SEETHA RAMA ELECTRICALS</div>
      ${header}
      <table class="invoice-table">
        <thead>
          <tr>
            <th>S.No</th><th>Item</th><th>Qty</th><th>Unit</th>
            <th>Rate</th><th>Disc%</th><th>Disc₹</th>
            <th>CGST%</th><th>SGST%</th><th>Tax₹</th><th>Total₹</th>
          </tr>
        </thead>
        <tbody>${rows}${summary}</tbody>
      </table>
      ${footer}
    </div>
  `;
}

/* -------------------------------------------
   PREVIEW INVOICE (SCROLL TO PRINT VIEW)
------------------------------------------- */
function generateAndPreviewInvoice() {
  const items = gatherItems();
  if (!items.length || !items[0].productId) {
    showToast("Please add at least one product line.", "warn"); return;
  }
  
  if (window.invoicePreviewSource !== "sales") {
    window.invoicePreviewSource = "builder";
  }
  
  const backBtn = document.getElementById("btnInvoiceBack");
  if (backBtn) {
    if (window.invoicePreviewSource === "sales") {
      backBtn.textContent = "← Back to Sales History";
    } else {
      backBtn.textContent = "← Back to Builder";
    }
  }

  renderInvoicePages(items);
  document.getElementById("app").style.display = "none";
  document.getElementById("invoiceContainer").style.display = "block";
  window.scrollTo(0, 0);
}

function renderInvoicePages(items) {
  const companyInfo = {
    name: "SEETHA RAMA ELECTRICALS",
    phone: "9441494703",
    gst: "36CWSPK2207B1ZQ",
    address: "Cherla, Bhadradri Kothagudem, Telangana - 507133"
  };
  const rawDate = document.getElementById("invoiceDate").value;
  const custInfo = {
    name:      document.getElementById("invoiceCustomerName").value  || "—",
    phone:     document.getElementById("invoiceCustomerPhone").value || "—",
    email:     document.getElementById("invoiceCustomerEmail").value || "",
    address:   document.getElementById("invoiceCustomerAddress").value || "—",
    invoiceNo: document.getElementById("invoiceNo").value,
    date: rawDate ? new Date(rawDate).toLocaleDateString("en-IN",{day:"2-digit",month:"2-digit",year:"numeric"}) : ""
  };

  let sub=0, cg=0, sg=0;
  items.forEach(p => { sub+=p.afterDisc; cg+=p.cgstAmt; sg+=p.sgstAmt; });
  const gt  = sub + cg + sg;
  const amountWords = numberToWords(Math.round(gt)) + " Rupees Only";

  // Paginate
  const pages = [];
  let rem = [...items];
  pages.push(rem.splice(0, ROWS_PER_FIRST_PAGE));
  while (rem.length > 0) pages.push(rem.splice(0, ROWS_PER_EXTRA_PAGE));

  document.getElementById("invoicePages").innerHTML = pages.map((pg, idx) =>
    buildInvoicePageHTML(pg, idx, pages.length, companyInfo, custInfo, amountWords)
  ).join("");
}

/* -------------------------------------------
   SAVE & EMAIL INVOICE
   FIX: pdfBase64 is NO LONGER sent to GAS.
   Sending a multi-MB base64 string inside JSON
   causes GAS to fail parsing → "Invalid action".
   New flow:
     1. Send lightweight invoice data to GAS
     2. GAS saves to sheet + sends HTML email
     3. Browser downloads PDF locally via Blob URL
------------------------------------------- */
async function saveAndEmailInvoice() {
  const name  = document.getElementById("invoiceCustomerName").value.trim();
  const phone = document.getElementById("invoiceCustomerPhone").value.trim();
  const email = document.getElementById("invoiceCustomerEmail").value.trim();
  const addr  = document.getElementById("invoiceCustomerAddress").value.trim();
  const invNo = document.getElementById("invoiceNo").value;
  const invoiceDate = document.getElementById("invoiceDate").value;

  if (!name)  { showToast("Customer Name is required.", "warn"); return; }
  if (!phone) { showToast("Customer Phone is required.", "warn"); return; }
  if (!email) { showToast("Customer Email is required for email delivery.", "warn"); return; }

  const items = gatherItems();
  if (!items.length || !items[0].productId) {
    showToast("Please select at least one product.", "warn"); return;
  }
  if (items.some(it => it.qty <= 0)) {
    showToast("All item quantities must be greater than 0.", "warn"); return;
  }

  // Check stock for all items as a final safeguard
  for (let i = 0; i < items.length; i++) {
    const item = items[i];
    const rows = document.querySelectorAll("#invDesktopBody tr");
    let matchedStock = 999999;
    for (let r of rows) {
      const sel = r.querySelector(".inv-sel");
      if (sel && sel.value === item.productId) {
        const opt = sel.options[sel.selectedIndex];
        matchedStock = parseFloat(opt.dataset.stock) || 0;
        break;
      }
    }
    
    if (item.qty > matchedStock) {
      showToast(`⚠️ Cannot save invoice. ${item.productName} has insufficient stock (Available: ${matchedStock}, Billed: ${item.qty}).`, "error");
      return;
    }
  }

  const btn = document.getElementById("saveInvoiceBtn");
  btn.disabled = true;
  btn.innerHTML = `<span class="spinner"></span> Saving…`;

  try {
    // ── Generate compressed PDF base64 first ────────────────────
    btn.innerHTML = `<span class="spinner"></span> Generating PDF Attachment…`;
    renderInvoicePages(items);
    await new Promise(r => setTimeout(r, 200)); // Let DOM settle

    let pdfBase64 = "";
    try {
      pdfBase64 = await generatePdfBase64();
    } catch (pdfErr) {
      console.warn("Could not generate base64 PDF for attachment:", pdfErr);
    }

    // ── Compute totals ──────────────────────────────────────────
    let subtotal = 0, totalDisc = 0, totalCGST = 0, totalSGST = 0;
    items.forEach(p => {
      subtotal  += p.afterDisc;
      totalDisc += p.discAmount;
      totalCGST += p.cgstAmt;
      totalSGST += p.sgstAmt;
    });
    const grandTotal      = Math.round(subtotal + totalCGST + totalSGST);
    const grossBeforeDisc = subtotal + totalDisc;
    const discountPercent = grossBeforeDisc > 0
      ? parseFloat(((totalDisc / grossBeforeDisc) * 100).toFixed(2)) : 0;

    // ── Payload with pdfBase64 ──────────────────────────────────
    const payload = {
      action:          "saveInvoice",
      invoiceNo:       invNo,
      invoiceDate:     invoiceDate,
      customerName:    name,
      customerPhone:   phone,
      customerEmail:   email,
      customerAddress: addr,
      subtotal,
      discountPercent,
      totalDiscount:   totalDisc,
      totalCGST,
      totalSGST,
      taxAmount:       totalCGST + totalSGST,
      grandTotal,
      amountWords:     numberToWords(grandTotal) + " Rupees Only",
      createdBy: (() => {
        try {
          const u = JSON.parse(localStorage.getItem("sre_user") || "{}");
          return u.name || u.username || "admin";
        } catch(e) { return "admin"; }
      })(),
      items: items.map(i => ({
        productId:   i.productId,
        productName: i.productName,
        qty:         i.qty,
        unit:        i.unit,
        rate:        i.rate,
        discount:    i.discount,
        discAmount:  i.discAmount,
        cgst:        i.cgst,
        sgst:        i.sgst,
        cgstAmt:     i.cgstAmt,
        sgstAmt:     i.sgstAmt,
        total:       i.total
      })),
      pdfBase64: pdfBase64
    };

    // ── Step 1: Save to Google Sheets + send HTML email via GAS ─
    btn.innerHTML = `<span class="spinner"></span> Saving & Sending…`;
    let result;
    try {
      const res  = await fetch(API_URL, { method: "POST", body: JSON.stringify(payload) });
      const text = await res.text();  // read as text first — GAS can return HTML on auth errors
      result = JSON.parse(text);
    } catch (fetchErr) {
      console.error("GAS fetch/parse error:", fetchErr);
      // Most likely: GAS needs re-authorization. Go to GAS editor → Run any function → Allow permissions.
      showToast("⚠️ GAS needs re-authorization. Open Apps Script editor → Run any function → Allow.", "error");
      return;
    }

    if (!result.success) {
      showToast(result.message || "Failed to save invoice.", "error");
      return;
    }

    // Invalidate caches since invoice creation updates sales registry and reduces inventory stock levels
    invalidateCache("sales");
    invalidateCache("inventory");

    // ── Step 2: Show print dialog for local PDF ──────────────────
    printInvoiceAsPDF(invNo);

    // ── Step 3: Show preview + result toast ──────────────────────
    document.getElementById("app").style.display = "none";
    document.getElementById("invoiceContainer").style.display = "block";
    window.scrollTo(0, 0);

    if (result.emailSent === false) {
      showToast(
        `✅ Invoice ${invNo} saved! Print dialog opened for PDF. ⚠️ Email failed: ${result.emailError || "Gmail permission needed."}`,
        "warn"
      );
    } else {
      showToast(`✅ Invoice ${invNo} saved & emailed with PDF to ${email}!`, "success");
    }

  } catch (err) {
    console.error("saveAndEmailInvoice error:", err);
    showToast("Error: " + (err.message || "Unknown error. Check console."), "error");
  } finally {
    btn.disabled = false;
    btn.innerHTML = `<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M19 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11l5 5v11a2 2 0 0 1-2 2z"/><polyline points="17 21 17 13 7 13 7 21"/><polyline points="7 3 7 8 15 8"/></svg> Save &amp; Email Invoice`;
  }
}

/* -------------------------------------------
   PDF GENERATION (iframe-based, A4 fixed)
------------------------------------------- */
async function generatePdfBase64() {
  const invoiceHTML = document.getElementById("invoicePages").innerHTML;
  const iframeDoc = `<!DOCTYPE html><html><head><meta charset="UTF-8">
  <style>
    *{margin:0;padding:0;box-sizing:border-box;font-family:Arial,sans-serif;}
    body{background:#fff;width:794px;}
    .invoice-page{width:794px;min-height:1123px;background:#fff;padding:45px 57px;position:relative;overflow:hidden;margin-bottom:20px;}
    .watermark{position:absolute;top:50%;left:50%;transform:translate(-50%,-50%) rotate(-45deg);font-size:52px;font-weight:bold;color:rgba(0,0,100,0.04);width:100%;text-align:center;white-space:nowrap;pointer-events:none;}
    .invoice-header{display:flex;justify-content:space-between;align-items:flex-start;border-bottom:2px solid #000;padding-bottom:10px;margin-bottom:14px;}
    .invoice-header h2{color:#0f172a;margin-bottom:4px;font-size:16px;font-weight:800;}
    .invoice-header p{font-size:12px;margin-bottom:3px;line-height:1.4;color:#334155;}
    .invoice-title{font-size:26px;font-weight:bold;color:#1e3a8a;}
    .customer-section{display:flex;justify-content:space-between;margin-bottom:14px;font-size:13px;line-height:1.7;}
    .invoice-table{width:100%;border-collapse:collapse;margin-top:8px;}
    .invoice-table th{background:#dbeafe;border:1px solid #000;padding:6px 4px;font-size:10.5px;text-align:center;font-weight:700;}
    .invoice-table td{border:1px solid #000;padding:6px 4px;font-size:10.5px;text-align:center;}
    .invoice-table td:nth-child(2){text-align:left;}
    .summary-row td{font-weight:700;background:#f8fafc;}
    .grand-total td{background:#1e3a8a;color:white;font-weight:bold;border-color:#1e3a8a;}
    .amount-words{margin-top:16px;padding:9px 11px;border:1px solid #000;font-size:13px;}
    .signature-section{margin-top:28px;display:flex;justify-content:flex-end;flex-direction:column;align-items:flex-end;}
    .signature-section img{width:130px;height:auto;}
    .signature-section div{text-align:center;font-weight:bold;font-size:13px;margin-top:5px;}
    .footer-note{margin-top:32px;text-align:center;font-size:12px;font-style:italic;border-top:1px solid #ccc;padding-top:9px;}
  </style></head><body>${invoiceHTML}</body></html>`;

  const iframe = document.createElement("iframe");
  iframe.style.cssText = "position:fixed;top:-9999px;left:-9999px;width:794px;height:1123px;border:none;visibility:hidden;";
  document.body.appendChild(iframe);

  await new Promise(resolve => {
    iframe.onload = resolve;
    iframe.contentDocument.open();
    iframe.contentDocument.write(iframeDoc);
    iframe.contentDocument.close();
  });
  await new Promise(r => setTimeout(r, 400));

  const { jsPDF } = window.jspdf;
  const pdf = new jsPDF("p", "mm", "a4");
  const A4W = 210;

  const pages = iframe.contentDocument.querySelectorAll(".invoice-page");
  for (let i = 0; i < pages.length; i++) {
    const canvas = await html2canvas(pages[i], {
      scale:2, useCORS:true, allowTaint:true, backgroundColor:"#ffffff",
      width:794, height:pages[i].scrollHeight, windowWidth:794
    });
    const imgData = canvas.toDataURL("image/jpeg", 0.85);
    const imgH    = (canvas.height * A4W) / canvas.width;
    if (i > 0) pdf.addPage();
    pdf.addImage(imgData, "JPEG", 0, 0, A4W, imgH);
  }

  document.body.removeChild(iframe);

  // Use arraybuffer → manual base64 to guarantee a valid PDF byte sequence
  // (datauristring can sometimes produce application/octet-stream MIME on some browsers)
  const arrayBuf = pdf.output("arraybuffer");
  const uint8 = new Uint8Array(arrayBuf);
  let binary = "";
  for (let i = 0; i < uint8.length; i++) {
    binary += String.fromCharCode(uint8[i]);
  }
  return btoa(binary);
}

/* -------------------------------------------
   DOWNLOAD PDF (from preview screen)
------------------------------------------- */
/* Shared helper — captures preview pages into a PDF and downloads via Blob URL.
   Blob URL approach is more reliable than pdf.save() across browsers and avoids
   file-type issues (some browsers mis-detect the MIME without a Blob trigger). */
async function _downloadPdfBlob(invNo) {
  const { jsPDF } = window.jspdf;
  const pdf   = new jsPDF("p", "mm", "a4");
  const A4W   = 210;
  const pages = document.querySelectorAll("#invoicePages .invoice-page");

  for (let i = 0; i < pages.length; i++) {
    const canvas = await html2canvas(pages[i], {
      scale: 2, useCORS: true, allowTaint: true,
      backgroundColor: "#ffffff",
      width: 794, height: pages[i].scrollHeight, windowWidth: 794
    });
    // Use JPEG (smaller than PNG → faster, avoids memory limits on multi-page)
    const imgData = canvas.toDataURL("image/jpeg", 0.92);
    const imgH    = (canvas.height * A4W) / canvas.width;
    if (i > 0) pdf.addPage();
    pdf.addImage(imgData, "JPEG", 0, 0, A4W, imgH);
  }

  // Blob URL download — browsers always treat this as a file download
  // and correctly set application/pdf MIME type
  const blob = pdf.output("blob");
  const url  = URL.createObjectURL(blob);
  const a    = document.createElement("a");
  a.href     = url;
  a.download = `Invoice-${invNo || "draft"}.pdf`;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

/* Called by the "Download PDF" button on the preview screen */
async function downloadPDF() {
  const invNo = document.getElementById("invoiceNo")?.value || "draft";
  const btn = document.querySelector("#invoiceContainer .btn-primary");
  const oldText = btn ? btn.innerHTML : "Download PDF";
  if (btn) {
    btn.disabled = true;
    btn.innerHTML = `<span class="spinner"></span> Generating PDF...`;
  }
  try {
    await _downloadPdfBlob(invNo);
    showToast("PDF downloaded successfully!", "success");
  } catch (err) {
    console.error("PDF download error:", err);
    showToast("Direct PDF download failed. Opening Print dialog instead...", "warn");
    printInvoiceAsPDF(invNo);
  } finally {
    if (btn) {
      btn.disabled = false;
      btn.innerHTML = oldText;
    }
  }
}

/* -------------------------------------------
   PRINT-BASED PDF GENERATION
   Uses browser window.print() — 100% reliable
   from file:// protocol, no CORS issues.
   User selects "Save as PDF" in the print dialog.
   Chrome/Edge auto-save: Ctrl+P → Save as PDF
------------------------------------------- */
function printInvoiceAsPDF(invNo) {
  // Get the rendered invoice HTML
  const pages = document.getElementById("invoicePages");
  if (!pages || !pages.innerHTML.trim()) {
    showToast("Please preview the invoice first before downloading.", "warn");
    return;
  }

  // Build a self-contained print window
  const printWin = window.open("", "_blank",
    "width=900,height=700,scrollbars=yes,resizable=yes");

  if (!printWin) {
    showToast("Popup blocked! Allow popups for this page and try again.", "error");
    return;
  }

  printWin.document.write(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>Invoice ${invNo || "draft"}</title>
  <style>
    * { margin:0; padding:0; box-sizing:border-box; font-family:Arial,sans-serif; }
    body { background:#fff; }
    .invoice-page {
      width:794px; min-height:1123px; background:#fff;
      padding:45px 57px; position:relative; overflow:hidden;
      margin:0 auto 20px; page-break-after:always;
    }
    .watermark {
      position:absolute; top:50%; left:50%;
      transform:translate(-50%,-50%) rotate(-45deg);
      font-size:52px; font-weight:bold; color:rgba(0,0,100,0.04);
      width:100%; text-align:center; white-space:nowrap; pointer-events:none;
    }
    .invoice-header { display:flex; justify-content:space-between; align-items:flex-start; border-bottom:2px solid #000; padding-bottom:10px; margin-bottom:14px; }
    .invoice-header h2 { color:#0f172a; margin-bottom:4px; font-size:16px; font-weight:800; }
    .invoice-header p { font-size:12px; margin-bottom:3px; line-height:1.4; color:#334155; }
    .invoice-title { font-size:26px; font-weight:bold; color:#1e3a8a; }
    .customer-section { display:flex; justify-content:space-between; margin-bottom:14px; font-size:13px; line-height:1.7; }
    .invoice-table { width:100%; border-collapse:collapse; margin-top:8px; }
    .invoice-table th { background:#dbeafe; border:1px solid #000; padding:6px 4px; font-size:10.5px; text-align:center; font-weight:700; }
    .invoice-table td { border:1px solid #000; padding:6px 4px; font-size:10.5px; text-align:center; }
    .invoice-table td:nth-child(2) { text-align:left; }
    .summary-row td { font-weight:700; background:#f8fafc; }
    .grand-total td { background:#1e3a8a; color:white; font-weight:bold; border-color:#1e3a8a; }
    .amount-words { margin-top:16px; padding:9px 11px; border:1px solid #000; font-size:13px; }
    .signature-section { margin-top:28px; display:flex; justify-content:flex-end; flex-direction:column; align-items:flex-end; }
    .signature-section img { width:130px; height:auto; }
    .footer-note { margin-top:32px; text-align:center; font-size:12px; font-style:italic; border-top:1px solid #ccc; padding-top:9px; }
    @media print {
      body { -webkit-print-color-adjust:exact; print-color-adjust:exact; }
      .invoice-page { page-break-after:always; margin:0; }
    }
  </style>
</head>
<body>
${pages.innerHTML}
</body>
</html>`);

  printWin.document.close();
  printWin.focus();

  // Wait for images to load then print
  setTimeout(() => {
    printWin.print();
    setTimeout(() => printWin.close(), 1000);
  }, 800);
}


/* -------------------------------------------
   CLOSE PREVIEW → BACK TO BUILDER
------------------------------------------- */
function closeInvoicePreview() {
  document.getElementById("invoiceContainer").style.display = "none";
  document.getElementById("app").style.display = "flex";
  
  if (window.invoicePreviewSource === "sales") {
    setActiveNav("navSales");
    showPage("sales");
  } else {
    setActiveNav("navInvoice");
    showPage("invoice");
  }
  
  const mainEl = document.querySelector("main");
  if (mainEl) mainEl.scrollTop = 0;
}

/* -------------------------------------------
   SEARCHABLE SELECT DROPDOWN COMPONENT
   ------------------------------------------- */
function makeSearchableSelect(selectEl, placeholderText) {
  if (!selectEl) return;

  // Prevent double initialization
  const existingContainer = selectEl.nextElementSibling;
  if (existingContainer && existingContainer.classList.contains('search-select-container')) {
    existingContainer.remove();
  }

  const container = document.createElement('div');
  container.className = 'search-select-container';

  const trigger = document.createElement('div');
  trigger.className = 'search-select-trigger';
  
  const dropdown = document.createElement('div');
  dropdown.className = 'search-select-dropdown';

  const searchInput = document.createElement('input');
  searchInput.type = 'text';
  searchInput.className = 'search-select-search-input';
  searchInput.placeholder = 'Type to search...';

  const optionsContainer = document.createElement('div');
  optionsContainer.className = 'search-select-options';

  dropdown.appendChild(searchInput);
  dropdown.appendChild(optionsContainer);
  container.appendChild(trigger);
  container.appendChild(dropdown);

  // Hide original select element
  selectEl.style.display = 'none';
  selectEl.parentNode.insertBefore(container, selectEl.nextSibling);

  // Function to render dropdown list items
  function renderOptions() {
    optionsContainer.innerHTML = '';
    const query = searchInput.value.toLowerCase().trim();
    let hasResults = false;

    Array.from(selectEl.options).forEach((opt, idx) => {
      // Don't show empty placeholder options in listing
      if (idx === 0 && opt.value === "") return;

      const text = opt.textContent;
      if (text.toLowerCase().includes(query)) {
        hasResults = true;
        const optDiv = document.createElement('div');
        optDiv.className = 'search-select-option';
        if (selectEl.value === opt.value) {
          optDiv.classList.add('selected');
        }
        optDiv.textContent = text;
        
        optDiv.addEventListener('click', (e) => {
          e.stopPropagation();
          selectEl.value = opt.value;
          selectEl.dispatchEvent(new Event('change'));
          updateTrigger();
          closeDropdown();
        });
        optionsContainer.appendChild(optDiv);
      }
    });

    if (!hasResults) {
      const noResultsDiv = document.createElement('div');
      noResultsDiv.className = 'search-select-option no-results';
      if (selectEl.id === "customerSelect") {
        noResultsDiv.style.cursor = 'default';
        noResultsDiv.innerHTML = `
          <div style="color: var(--slate-500); margin-bottom: 8px;">No matches found</div>
          <button type="button" class="btn btn-primary btn-sm" style="width: 100%; display: flex; align-items: center; justify-content: center; gap: 6px; padding: 6px 12px; font-size: 13px;" onclick="openCustomerModalFromInvoice('${searchInput.value.trim().replace(/'/g, "\\'")}')">
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><line x1="12" y1="5" x2="12" y2="19"></line><line x1="5" y1="12" x2="19" y2="12"></line></svg>
            Add New Customer
          </button>
        `;
      } else if (selectEl.classList.contains("inv-sel") || selectEl.classList.contains("m-sel")) {
        noResultsDiv.style.cursor = 'default';
        noResultsDiv.innerHTML = `
          <div style="color: var(--slate-500); margin-bottom: 8px;">No matches found</div>
          <button type="button" class="btn btn-primary btn-sm" style="width: 100%; display: flex; align-items: center; justify-content: center; gap: 6px; padding: 6px 12px; font-size: 13px;" onclick="openProductModalFromInvoice('${searchInput.value.trim().replace(/'/g, "\\'")}')">
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><line x1="12" y1="5" x2="12" y2="19"></line><line x1="5" y1="12" x2="19" y2="12"></line></svg>
            Add New Product
          </button>
        `;
      } else {
        noResultsDiv.textContent = 'No matches found';
      }
      optionsContainer.appendChild(noResultsDiv);
    }
  }

  // Update text inside trigger display
  function updateTrigger() {
    const selectedOpt = selectEl.options[selectEl.selectedIndex];
    trigger.textContent = selectedOpt && selectedOpt.value !== "" ? selectedOpt.textContent : (placeholderText || 'Select...');
  }

  function openDropdown() {
    // Close other open searchable selects first
    document.querySelectorAll('.search-select-container.open').forEach(c => {
      if (c !== container) c.classList.remove('open');
    });
    container.classList.add('open');
    searchInput.value = '';
    renderOptions();
    // Use short timeout to ensure input element is focusable
    setTimeout(() => searchInput.focus(), 50);
  }

  function closeDropdown() {
    container.classList.remove('open');
  }

  trigger.addEventListener('click', (e) => {
    e.stopPropagation();
    if (container.classList.contains('open')) {
      closeDropdown();
    } else {
      openDropdown();
    }
  });

  searchInput.addEventListener('click', (e) => {
    e.stopPropagation();
  });

  searchInput.addEventListener('input', () => {
    renderOptions();
  });

  // Intercept value property changes so programmatic updates (such as desktop <-> mobile syncs) update the trigger UI
  const descriptor = Object.getOwnPropertyDescriptor(HTMLSelectElement.prototype, 'value');
  if (descriptor && !selectEl.hasOwnProperty('value')) {
    Object.defineProperty(selectEl, 'value', {
      configurable: true,
      get: function() {
        return descriptor.get.call(this);
      },
      set: function(val) {
        descriptor.set.call(this, val);
        updateTrigger();
      }
    });
  }

  // Initial render & listen to change event
  updateTrigger();
  selectEl.addEventListener('change', updateTrigger);
}

// Close searchable dropdowns when clicking outside
document.addEventListener('click', () => {
  document.querySelectorAll('.search-select-container.open').forEach(c => {
    c.classList.remove('open');
  });
});

function setInvoiceFieldsReadOnly(readOnly) {
  const container = document.getElementById("invoice");
  if (!container) return;

  const inputs = container.querySelectorAll("input, select, textarea, button");
  inputs.forEach(el => {
    if (el.id === "saveInvoiceBtn" || 
        el.classList.contains("btn-add-item") || 
        el.classList.contains("col-del") || 
        el.tagName === "INPUT" || 
        el.tagName === "SELECT" || 
        el.tagName === "TEXTAREA") {
      el.disabled = readOnly;
      if (readOnly) {
        el.style.opacity = "0.75";
      } else {
        el.style.opacity = "";
      }
    }
  });

  const delButtons = container.querySelectorAll(".inv-btn-del, .inv-card-del, .inv-btn-del button");
  delButtons.forEach(btn => {
    btn.style.display = readOnly ? "none" : "";
  });
  
  const addBtn = container.querySelector(".btn-add-item");
  if (addBtn) {
    addBtn.style.display = readOnly ? "none" : "";
  }

  const searchSelects = container.querySelectorAll(".search-select-trigger, .search-select-input");
  searchSelects.forEach(el => {
    if (readOnly) {
      el.style.pointerEvents = "none";
      el.style.opacity = "0.7";
    } else {
      el.style.pointerEvents = "";
      el.style.opacity = "";
    }
  });

  const saveBtn = document.getElementById("saveInvoiceBtn");
  if (saveBtn) {
    saveBtn.style.display = readOnly ? "none" : "";
  }
}

function openCustomerModalFromInvoice(name) {
  if (typeof openCustomerModal === 'function') {
    openCustomerModal();
    const nameInput = document.getElementById("c_name");
    if (nameInput) {
      nameInput.value = name;
    }
    window.customerCreatedFromInvoice = true;
  }
}

function openProductModalFromInvoice(name) {
  if (typeof openProductModal === 'function') {
    openProductModal();
    const nameInput = document.getElementById("p_name");
    if (nameInput) {
      nameInput.value = name;
    }
    window.productCreatedFromInvoice = true;
  }
}

function refreshProductSelects() {
  const productOptions = inventoryProducts.map(p =>
    `<option value="${p.productId}" data-rate="${p.rate}" data-unit="${p.unit||'Nos'}" data-cgst="${p.cgst||9}" data-sgst="${p.sgst||9}" data-stock="${p.stock}">${p.productName}</option>`
  ).join("");

  document.querySelectorAll(".inv-sel, .m-sel").forEach(sel => {
    const currentValue = sel.value;
    const isMobile = sel.classList.contains('m-sel');
    const placeholder = isMobile ? '— Select Product —' : '— Select —';
    sel.innerHTML = `<option value="">${placeholder}</option>` + productOptions;
    sel.value = currentValue;
    makeSearchableSelect(sel, placeholder);
  });
}


